mapper.update:
UPDATE platform_v3.ux_favorite
SET sort_order = #{sortOrder}
WHERE fav_id = #{favId}

mapper.select:
SELECT pref_id, employee_no, category, channel, enabled
FROM platform_v3.ux_notify_pref
WHERE employee_no = #{employeeNo}
  AND category    = #{category}
  AND channel     = #{channel}
LIMIT 1
